import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SafeBufferHandlingExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Properly sized buffer with bounds checking
        byte[] buffer = new byte[Math.min(userInput.length(), 10)];

        // Copy only up to the length of the buffer
        System.arraycopy(userInput.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, buffer.length);

        System.out.println("Buffer content: " + new String(buffer, StandardCharsets.UTF_8));
    }
}

### Explanation:
취약유형: Buffer Overflow
